}

.cc-btn-secondary {
    background: #6c757d;
    color: white;
}

.cc-btn-success {
    background: #28a745;
    color: white;
}

.cc-btn-warning {
    background: #ffc107;
    color: #212529;
}

.cc-btn-danger {
    background: #dc3545;
    color: white;
}

.cc-btn-outline {
    background: transparent;
    border: 2px solid #00BCD1;
    color: #00BCD1;
}

.cc-btn-ghost {
    background: transparent;
    color: #00BCD1;
    border: none;
}

.cc-btn-disabled {
    background: #e9ecef;
    color: #6c757d;
    cursor: not-allowed;
}

.cc-btn:hover:not(.cc-btn-disabled) {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0,0,0,0.2);
}

/* ===== BADGES STYLES ===== */
.cc-badges-demo {
    display: flex;
    flex-wrap: wrap;
    gap: 15px;
    align-items: center;
}

.cc-badge {
    padding: 6px 12px;
    border-radius: 15px;
    font-size: 0.8rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.cc-badge-primary {
    background: #00BCD1;
    color: white;
}

.cc-badge-success {
    background: #28a745;
    color: white;
}

.cc-badge-warning {
    background: #ffc107;
    color: #212529;
}

.cc-badge-danger {
    background: #dc3545;
    color: white;
}

.cc-badge-info {
    background: #17a2b8;
    color: white;
}

.cc-badge-light {
