    color: #6c757d;
    border: 1px solid #dee2e6;
}

.cc-badge-dark {
    background: #343a40;
    color: white;
}

/* ===== PROGRESS BARS STYLES ===== */
.cc-progress-demo {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.cc-progress-item {
    display: flex;
