    background: linear-gradient(135deg, #00BCD1, #44A08D);
    border-radius: 10px;
    transition: width 0.5s ease;
}

.cc-progress-success .cc-progress-fill {
    background: #28a745;
}

.cc-progress-warning .cc-progress-fill {
    background: #ffc107;
}

.cc-progress-text {
    min-width: 40px;
