    font-weight: 600;
}

.cc-accordion-toggle {
    font-size: 1.5rem;
    color: #00BCD1;
    font-weight: 300;
    transition: transform 0.3s ease;
}

.cc-accordion-content {
    padding: 15px 20px;
    background: white;
    color: #666;
    line-height: 1.6;
    display: none;
}

.cc-accordion-content p {
    margin: 0;
}

/* ========================================
   RESPONSIVE DESIGN
======================================== */

@media (max-width: 768px) {
