/* Reset and base styles */
.rita-container * {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

.rita-container {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  line-height: 1.6;
  color: #ffffff;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

/* Header Section */
.rita-header {
  background: linear-gradient(135deg, #00BCD1 0%, #44A08D 100%);
  color: white;
  padding: 60px 0;
  text-align: center;
  border-radius: 20px;
  margin-bottom: 40px;
  box-shadow: 0 10px 30px rgba(0, 188, 209, 0.3);
}

.header-content {
  max-width: 800px;
  margin: 0 auto;
  padding: 0 20px;
}

.main-title {
  font-family: 'Sansita Swashed', cursive;
  font-size: 3.5em;
  font-weight: 700;
  margin-bottom: 20px;
  text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
  letter-spacing: -1px;
}

.subtitle {
  font-size: 1.2em;
  font-weight: 300;
  opacity: 0.95;
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.5;
}

/* Hero Section */
.hero-section {
  margin-bottom: 60px;
}

.hero-image {
  position: relative;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 15px 35px rgba(0,0,0,0.1);
  height: 400px;
}

.hero-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.hero-image:hover img {
  transform: scale(1.05);
}

.hero-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: linear-gradient(transparent, rgba(0,0,0,0.8));
  color: white;
  padding: 40px 30px 30px;
  text-align: center;
