.cta-content p {
  font-size: 1.2em;
  margin-bottom: 30px;
  opacity: 0.95;
  line-height: 1.6;
}

.cta-button {
  display: inline-block;
  background: white;
  color: #00BCD1;
  padding: 18px 40px;
  border-radius: 30px;
  text-decoration: none;
  font-weight: 700;
  font-size: 1.1em;
  transition: all 0.3s ease;
  box-shadow: 0 8px 25px rgba(0,0,0,0.2);
}

.cta-button:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 30px rgba(0,0,0,0.3);
  text-decoration: none;
  color: #44A08D;
}

/* Responsive Design */
@media (max-width: 768px) {
  .rita-container {
    padding: 0 15px;
  }

  .main-title {
    font-size: 2.5em;
  }

  .subtitle {
    font-size: 1em;
  }

  .section-title {
    font-size: 2em;
  }

  .hero-image {
    height: 300px;
  }

  .hero-overlay h2 {
    font-size: 1.8em;
  }

  .hero-overlay p {
    font-size: 1em;
  }

  .products-grid,
  .gallery-grid,
  .contact-cards {
    grid-template-columns: 1fr;
    gap: 20px;
  }

  .products-section,
  .contact-content {
    padding: 40px 20px;
  }

  .product-card,
  .contact-card {
    padding: 30px 20px;
  }

  .cta-content h2 {
    font-size: 2em;
  }

  .cta-content p {
    font-size: 1.1em;
  }
}

@media (max-width: 480px) {
  .main-title {
    font-size: 2em;
  }

  .section-title {
    font-size: 1.8em;
  }

  .hero-overlay {
    padding: 20px 15px 15px;
  }

  .hero-overlay h2 {
    font-size: 1.5em;
  }

  .product-card,
  .contact-card {
    padding: 25px 15px;
  }

  .cta-content h2 {
    font-size: 1.8em;
  }

  .cta-button {
    padding: 15px 30px;
    font-size: 1em;
  }
